import { defineStore } from 'pinia'

export const useDataStore = defineStore('data', {
  state: () => ({
    temps: []
  }),
  getters: {
    // ...
  },
  actions: {
    loadData (api) {
      api.get('monitoring-data.json').then(
        res => { this.temps = res.data },
        error => { alert(error); return Promise.reject(error) } // add some notify
      )
    }
  }
})
